INSERT INTO aihub.workflow_definitions ("Id", "Name", "Data", "CreatedAt", "UpdatedAt", "ProjectId", "Visibility") VALUES ('investment-committee-concurrent', 'Investment Committee — Análise Paralela', '{"ProjectId":"default","Id":"investment-committee-concurrent","Name":"Investment Committee \u2014 An\u00E1lise Paralela","Description":"5 especialistas analisam em paralelo (economia macro, risco de carteira, tributa\u00E7\u00E3o, risco sist\u00EAmico, gest\u00E3o). O resultado \u00E9 a consolida\u00E7\u00E3o autom\u00E1tica das 5 vis\u00F5es.","Version":"1.1.0","OrchestrationMode":"Concurrent","Agents":[{"AgentId":"economista-chefe","Role":null},{"AgentId":"portfolio-risk-analyzer","Role":null},{"AgentId":"tributarista","Role":null},{"AgentId":"chief-risk-officer","Role":null},{"AgentId":"gestor-de-portfolio","Role":null}],"Executors":[],"Edges":[],"RoutingRules":[],"Trigger":null,"Configuration":{"MaxRounds":null,"TimeoutSeconds":300,"EnableHumanInTheLoop":false,"CheckpointMode":"InMemory","ExposeAsAgent":false,"ExposedAgentDescription":null,"InputMode":"Standalone","MaxHistoryMessages":50,"MaxAgentInvocations":20,"MaxTokensPerExecution":50000,"MaxCostUsdPerExecution":null,"OutputNodes":null,"MaxConcurrentExecutions":null},"Metadata":{"domain":"capital-markets","category":"investment-committee","study-case":"concurrent-mode","parallel-agents":"economista-chefe,portfolio-risk-analyzer,tributarista,chief-risk-officer,gestor-de-portfolio"},"Visibility":"project","CreatedAt":"2026-04-13T00:49:37.1920944Z","UpdatedAt":"2026-04-13T00:49:37.1920944Z"}', '2026-04-13 00:49:37.192541+00', '2026-04-13 00:49:37.192541+00', 'default', 'project') ON CONFLICT ("Id") DO NOTHING;
